{
  "steps": [
    {
      "step_id": "cb_step_1",
      "title": "Select CT Volume",
      "simple": "Choose the CT scan of the fractured long bone from the list.",
      "detailed": "This volume will be used for all subsequent segmentation and 3D reconstruction steps. Select the CT scan that clearly shows both the proximal (reference) and distal (moving) fracture fragments."
    },
    {
      "step_id": "cb_step_2",
      "title": "Create Reference Segmentation",
      "simple": "Switch to the Segment Editor module and create a new segmentation named 'Reference_Segmentation'.",
      "detailed": "This segmentation will hold the bone fragment that will serve as the stable reference (typically the proximal fragment). Accurate segmentation is critical for successful fracture reduction planning."
    },
    {
      "step_id": "cb_step_3",
      "title": "Add Reference Segment",
      "simple": "Click the 'Add' button and rename the new segment to 'Reference_Segment'.",
      "detailed": "This segment will contain the voxels belonging to the reference bone fragment. Naming it clearly helps avoid confusion when the moving fragment is created later."
    },
    {
      "step_id": "cb_step_4",
      "title": "Open Threshold Tool",
      "simple": "Click the 'Threshold' button in the Segment Editor.",
      "detailed": "Thresholding isolates bone tissue from soft tissue by Hounsfield unit range. This prepares for automated segmentation of the reference fragment."
    },
    {
      "step_id": "cb_step_5",
      "title": "Set Threshold Range",
      "simple": "Adjust the threshold slider to include only bone voxels on the reference fragment.",
      "detailed": "Set the lower and upper bounds to capture cortical and trabecular bone while excluding surrounding soft tissue and air. The range typically spans 150–3000 HU for adult bone."
    },
    {
      "step_id": "cb_step_6",
      "title": "Apply Threshold",
      "simple": "Click the 'Apply' button to create the threshold-based segmentation.",
      "detailed": "This generates a binary mask of all bone voxels within the defined range. The mask will include both fragments and other bones, which will be cleaned up in the next steps."
    },
    {
      "step_id": "cb_step_7",
      "title": "Open Islands Tool",
      "simple": "Click the 'Islands' button in the Segment Editor.",
      "detailed": "The Islands tool separates disconnected bone regions into individual islands, allowing you to select only the reference fragment and discard the rest."
    },
    {
      "step_id": "cb_step_8",
      "title": "Select Keep Selected Island",
      "simple": "Choose the 'Keep selected island' option from the Islands menu.",
      "detailed": "This tool keeps only the island you click on and removes all other disconnected bone regions, isolating the intended reference fragment."
    },
    {
      "step_id": "cb_step_9",
      "title": "Click Reference Fragment",
      "simple": "Click on the reference bone fragment in a slice view to keep that island.",
      "detailed": "This tells the tool which island to retain — typically the proximal fragment. All other bone (including the moving fragment) will be discarded from this segmentation."
    },
    {
      "step_id": "cb_step_10",
      "title": "Hide Reference Segment",
      "simple": "Toggle visibility of 'Reference_Segment' off so it does not interfere with the next steps.",
      "detailed": "Hiding the completed reference segment keeps the view clean while you create the segmentation for the moving fragment."
    },
    {
      "step_id": "cb_step_11",
      "title": "Create Moving Segmentation",
      "simple": "Create a new segmentation named 'Moving_Segmentation' in the Segment Editor.",
      "detailed": "This segmentation will hold the other bone fragment (typically the distal fragment). It is moved relative to the reference during fracture reduction."
    },
    {
      "step_id": "cb_step_12",
      "title": "Add Moving Segment",
      "simple": "Click 'Add' and rename the new segment to 'Moving_Segment'.",
      "detailed": "This segment will contain the bone voxels of the moving fragment. Clear naming prevents confusion with the already-completed reference segment."
    },
    {
      "step_id": "cb_step_13",
      "title": "Open Threshold Tool",
      "simple": "Click the 'Threshold' button again for the moving segmentation.",
      "detailed": "Repeat the threshold operation to isolate the moving fragment's bone tissue within its own segmentation."
    },
    {
      "step_id": "cb_step_14",
      "title": "Set Moving Threshold Range",
      "simple": "Adjust the threshold slider to capture bone voxels of the moving fragment.",
      "detailed": "Use a bone-appropriate threshold range (similar to step 5) to capture the moving fragment while excluding soft tissue."
    },
    {
      "step_id": "cb_step_15",
      "title": "Apply Threshold",
      "simple": "Click 'Apply' to create the threshold mask for the moving segment.",
      "detailed": "This creates a binary mask that may include both fragments again; the next steps will isolate the moving fragment using the Islands tool."
    },
    {
      "step_id": "cb_step_16",
      "title": "Open Islands Tool",
      "simple": "Click the 'Islands' button again.",
      "detailed": "Prepare to isolate the moving fragment by selecting the appropriate island."
    },
    {
      "step_id": "cb_step_17",
      "title": "Select Keep Selected Island",
      "simple": "Choose 'Keep selected island' from the Islands menu.",
      "detailed": "This will keep only the island you click next, isolating the moving fragment from any other bone in the mask."
    },
    {
      "step_id": "cb_step_18",
      "title": "Click Moving Fragment",
      "simple": "Click on the moving bone fragment in a slice view to keep that island.",
      "detailed": "This selects the distal fragment as the moving fragment. The reference fragment and other bones will be removed from this segmentation."
    },
    {
      "step_id": "cb_step_19",
      "title": "Hide Moving Segment",
      "simple": "Toggle visibility of 'Moving_Segment' off.",
      "detailed": "Hiding the completed moving segment keeps the view uncluttered before proceeding to 3D reconstruction."
    },
    {
      "step_id": "cb_step_20",
      "title": "Select Reference Segmentation",
      "simple": "In the extension panel, choose 'Reference_Segmentation' as the reference segmentation.",
      "detailed": "This tells the extension which segmentation contains the reference fragment for 3D model creation and fracture analysis."
    },
    {
      "step_id": "cb_step_21",
      "title": "Reconstruct Reference Model",
      "simple": "Click the '3D Reconstruction (reference)' button.",
      "detailed": "This generates a 3D surface model of the reference bone fragment, which will be used for fracture surface detection and alignment."
    },
    {
      "step_id": "cb_step_22",
      "title": "Select Moving Segmentation",
      "simple": "Choose 'Moving_Segmentation' as the moving segmentation.",
      "detailed": "This designates the segmentation containing the fragment that will be repositioned to achieve anatomical reduction."
    },
    {
      "step_id": "cb_step_23",
      "title": "Reconstruct Moving Model",
      "simple": "Click the '3D Reconstruction (moving)' button.",
      "detailed": "This creates a 3D model of the moving fragment. Both 3D models are needed for fracture surface detection and virtual reduction."
    },
    {
      "step_id": "cb_step_24",
      "title": "Add Reference ROI",
      "simple": "Click the 'Add / reset reference ROI' button to create a region of interest around the reference fragment.",
      "detailed": "The ROI defines the volume used for fracture surface detection on the reference fragment. It should tightly enclose the fracture end."
    },
    {
      "step_id": "cb_step_25",
      "title": "Adjust Reference ROI",
      "simple": "Drag the ROI handles to enclose the fractured portion of the reference model.",
      "detailed": "Narrow the ROI so it only covers the fracture site — not the entire bone. This focuses the fracture detection algorithm on the matching surfaces that need to align during reduction."
    },
    {
      "step_id": "cb_step_26",
      "title": "Add Moving ROI",
      "simple": "Click the 'Add / reset moving ROI' button to create a region of interest around the moving fragment.",
      "detailed": "This ROI will be used to detect the corresponding fracture surface on the moving fragment."
    },
    {
      "step_id": "cb_step_27",
      "title": "Adjust Moving ROI",
      "simple": "Drag the ROI handles to enclose the fractured portion of the moving model.",
      "detailed": "Tightly enclose the fracture end of the moving fragment. The fracture detection algorithm will search for matching surface geometry within both ROIs to compute the optimal reduction."
    },
    {
      "step_id": "cb_step_28",
      "title": "Detect Fracture Surfaces",
      "simple": "Click the 'Detect fracture surfaces' button.",
      "detailed": "The algorithm identifies the opposing fracture surfaces within the defined ROIs. These surfaces will be used as targets for aligning the fragments."
    },
    {
      "step_id": "cb_step_29",
      "title": "Reduce Fracture",
      "simple": "Click the 'Reduce fracture' button to align the moving fragment to the reference fragment.",
      "detailed": "This computes the rigid transformation that best fits the fracture surfaces together, virtually reducing the fracture. The result is a transformation that can be applied to the moving fragment."
    },
    {
      "step_id": "cb_step_30",
      "title": "Manual Adjustment Option",
      "simple": "Check the box if you want to manually adjust the moving fragment position after automatic reduction.",
      "detailed": "If the automatic result looks good, skip this step. Otherwise, checking the box enables manual fine-tuning of the fragment alignment using the 3D view."
    },
    {
      "step_id": "cb_step_31",
      "title": "Inspect and Adjust View",
      "simple": "Rotate and zoom the 3D view to inspect the alignment of the moving fragment.",
      "detailed": "Carefully examine the gap and rotation between fragments from multiple angles. A clear vantage helps you decide if further adjustment with the transform tools is needed."
    },
    {
      "step_id": "cb_step_32",
      "title": "Harden Transform",
      "simple": "Click the 'Harden transform into moving fragment' button to finalize the reduction.",
      "detailed": "This permanently applies the transformation to the moving fragment's geometry, making the reduction a fixed part of the model for subsequent planning or surgical guide creation."
    }
  ]
}
